# Blueprint for an action-taking travel agent
travel_blueprint = {
    "scenario": "User books cheapest available flight to Berlin",
    "steps": [
        {
            "id": "S1", "label": "Intent capture",
            "autonomy_level": "automatic",
            "tools": [],
            "llm": "intent + parameter extraction",
            "confirmation_gate": False
        },
        {
            "id": "S2", "label": "Search",
            "autonomy_level": "automatic",
            "tools": ["search_flights(origin, dest, date)"],
            "llm": "summarise results, rank by price",
            "confirmation_gate": False
        },
        {
            "id": "S3", "label": "Present options",
            "autonomy_level": "frontstage",
            "tools": [],
            "llm": "format comparison card for user",
            "confirmation_gate": False
        },
        {
            "id": "S4", "label": "Confirm booking",
            "autonomy_level": "requires_human_approval",  # crosses autonomy line
            "tools": [],
            "llm": "present summary; request explicit confirmation",
            "confirmation_gate": True   # gate before S5
        },
        {
            "id": "S5", "label": "Book",
            "autonomy_level": "post_approval",
            "tools": ["book_flight(flight_id, passenger_details)"],
            "llm": "parse confirmation; format booking receipt",
            "confirmation_gate": False
        }
    ]
}

for step in travel_blueprint["steps"]:
    gate = " [CONFIRMATION GATE]" if step.get("confirmation_gate") else ""
    tools = ", ".join(step["tools"]) if step["tools"] else "none"
    print(f"{step['id']} {step['label']:25} | {step['autonomy_level']:30} | tools: {tools}{gate}")
